import crypto from 'node:crypto';
import { FileModel } from '../models/file.model';
import { FileContentModel } from '../models/file-content.model';
import { S3Client, PutObjectCommand } from '@aws-sdk/client-s3';

const s3 = new S3Client({ region: process.env.AWS_REGION! });
const BUCKET = process.env.S3_BUCKET!;

export const fileVersionService = {
  async upload(orgId: string, path: string, buffer: Buffer, contentType: string, userId: string, comment?: string) {
    const hash = crypto.createHash('sha256').update(buffer).digest('hex');
    const existing = await FileContentModel.findById(hash);
    if (!existing) {
      const s3Key = `content/${hash}`;
      await s3.send(new PutObjectCommand({ Bucket: BUCKET, Key: s3Key, Body: buffer, ContentType: contentType }));
      await FileContentModel.create({ _id: hash, size: buffer.length, contentType, s3Key, refCount: 1 });
    } else {
      await FileContentModel.updateOne({ _id: hash }, { $inc: { refCount: 1 } });
    }
    const file = await FileModel.findOneAndUpdate(
      { orgId, path },
      { $push: { versions: { versionId: { $size: { $ifNull: ['$versions', []] } } as any, contentHash: hash, uploadedBy: userId, uploadedAt: new Date(), comment } } as any },
      { upsert: true, new: true }
    );
    file!.latestVersion = file!.versions.length - 1;
    await file!.save();
    return file!;
  },
  async restoreVersion(orgId: string, path: string, versionId: number, userId: string) {
    const file = await FileModel.findOne({ orgId, path });
    if (!file) throw new Error('NOT_FOUND');
    const v = file.versions[versionId];
    if (!v) throw new Error('VERSION_NOT_FOUND');
    await FileContentModel.updateOne({ _id: v.contentHash }, { $inc: { refCount: 1 } });
    file.versions.push({ versionId: file.versions.length, contentHash: v.contentHash, uploadedBy: userId as any, uploadedAt: new Date(), comment: `Restored from v${versionId}` });
    file.latestVersion = file.versions.length - 1;
    await file.save();
    return file;
  }
};

import { useEffect, useState } from 'react';

type Version = { versionId: number; uploadedAt: string; uploadedBy: string; comment?: string };

export function FileVersions({ orgId, path }: { orgId: string; path: string }) {
  const [versions, setVersions] = useState<Version[]>([]);
  useEffect(() => { fetch(`/api/files/${orgId}/${encodeURIComponent(path)}/versions`).then(r => r.json()).then(d => setVersions(d.versions)); }, [orgId, path]);
  const restore = async (versionId: number) => {
    await fetch(`/api/files/${orgId}/${encodeURIComponent(path)}/restore`, { method: 'POST', credentials: 'include', headers: { 'content-type': 'application/json' }, body: JSON.stringify({ versionId }) });
    fetch(`/api/files/${orgId}/${encodeURIComponent(path)}/versions`).then(r => r.json()).then(d => setVersions(d.versions));
  };
  return (
    <ul className="divide-y">
      {versions.map(v => (
        <li key={v.versionId} className="py-2 flex justify-between">
          <div>v{v.versionId} - {new Date(v.uploadedAt).toLocaleString()} - {v.comment ?? ''}</div>
          <button onClick={() => restore(v.versionId)} className="text-blue-600">Restore</button>
        </li>
      ))}
    </ul>
  );
}

