const PRESENCE_TTL = 60;

export async function markSocketActive(userId: string) {
  await redis.set(`socket-active:${userId}`, '1', { EX: PRESENCE_TTL });
}

export async function notifyUser(userId: string, payload: { title: string; body: string; data?: Record<string, unknown> }) {
  const active = await redis.get(`socket-active:${userId}`);
  if (active) {
    io.of('/notifications').to(`user:${userId}`).emit('notify', payload);
    return;
  }
  const prefs = await UserPreferenceModel.findOne({ userId }).lean();
  if (prefs?.pushEnabled === false) return;
  await enqueue.push({ userId, ...payload });
}

import { Server, Socket } from 'socket.io';
import { markSocketActive } from '../services/notification.service';

interface AuthedSocket extends Socket { data: { userId: string } }

export function attachNotificationNamespace(io: Server) {
  const ns = io.of('/notifications');
  ns.on('connection', (socket: AuthedSocket) => {
    socket.join(`user:${socket.data.userId}`);
    void markSocketActive(socket.data.userId);
    const t = setInterval(() => markSocketActive(socket.data.userId), 30_000);
    socket.on('disconnect', () => clearInterval(t));
  });
}

import { DeviceTokenModel } from '../models/device-token.model';
import { sendFCM, sendAPNs } from '../infra/push';

export async function processPush(data: { userId: string; title: string; body: string; data?: Record<string, unknown> }) {
  const tokens = await DeviceTokenModel.find({ userId: data.userId }).lean();
  for (const tok of tokens) {
    if (tok.platform === 'fcm') await sendFCM(tok.token, data);
    else if (tok.platform === 'apns') await sendAPNs(tok.token, data);
  }
}

