import { Canvas, useFrame, ThreeEvent } from '@react-three/fiber';
import { Text, OrbitControls } from '@react-three/drei';
import { Suspense, useMemo, useRef, useState } from 'react';
import * as THREE from 'three';

type Bar = { label: string; value: number; targetHeight: number; currentHeight: number; color: string };

function Bars({ bars, onHover }: { bars: Bar[]; onHover: (b: Bar | null) => void }) {
  const groupRef = useRef<THREE.Group>(null);
  useFrame(() => {
    for (const b of bars) b.currentHeight += (b.targetHeight - b.currentHeight) * 0.15;
    if (!groupRef.current) return;
    groupRef.current.children.forEach((child, i) => {
      const b = bars[i]; if (!b) return;
      child.scale.y = Math.max(0.001, b.currentHeight);
      child.position.y = b.currentHeight / 2;
    });
  });
  return (
    <group ref={groupRef}>
      {bars.map((b, i) => (
        <mesh key={b.label} position={[i * 1.5 - bars.length * 0.75, 0, 0]} onPointerOver={() => onHover(b)} onPointerOut={() => onHover(null)}>
          <boxGeometry args={[1, 1, 1]} />
          <meshStandardMaterial color={b.color} />
        </mesh>
      ))}
      {bars.map((b, i) => <Text key={b.label} position={[i * 1.5 - bars.length * 0.75, -0.4, 0]} fontSize={0.2} color="#333">{b.label}</Text>)}
    </group>
  );
}

export function BarChart3D({ data }: { data: { label: string; value: number }[] }) {
  const max = Math.max(1, ...data.map(d => d.value));
  const barsRef = useRef<Bar[]>([]);
  const [hovered, setHovered] = useState<Bar | null>(null);
  const bars = useMemo(() => data.map((d, i) => {
    const existing = barsRef.current.find(b => b.label === d.label);
    return existing
      ? { ...existing, value: d.value, targetHeight: d.value / max * 4 }
      : { label: d.label, value: d.value, targetHeight: d.value / max * 4, currentHeight: 0, color: `hsl(${(i * 47) % 360} 70% 55%)` };
  }), [data, max]);
  barsRef.current = bars;
  return (
    <div className="w-full h-96 relative">
      <Canvas camera={{ position: [0, 4, 8], fov: 50 }} dpr={[1, 2]}>
        <ambientLight intensity={0.6} />
        <directionalLight position={[5, 10, 5]} intensity={0.8} />
        <Suspense fallback={null}><Bars bars={bars} onHover={setHovered} /></Suspense>
        <OrbitControls />
      </Canvas>
      {hovered && <div className="absolute top-2 left-2 bg-black text-white px-2 py-1 text-xs rounded">{hovered.label}: {hovered.value}</div>}
    </div>
  );
}

