import { WalletModel } from '../models/wallet.model';
import { WalletEventModel } from '../models/wallet-event.model';
import { startSession } from 'mongoose';

export const walletService = {
  async deposit(walletId: string, orgId: string, amount: number, by: string, refId: string) {
    const session = await startSession();
    try {
      await session.withTransaction(async () => {
        const wallet = await WalletModel.findById(walletId).session(session);
        if (!wallet) throw new Error('NOT_FOUND');
        const sequence = (wallet.lastSequence ?? 0) + 1;
        await WalletEventModel.create([{ walletId, orgId, sequence, type: 'deposit', amount, refId, by }], { session });
        wallet.balance += amount;
        wallet.lastSequence = sequence;
        await wallet.save({ session });
      });
    } finally { session.endSession(); }
  },
  async withdraw(walletId: string, orgId: string, amount: number, by: string, refId: string) {
    const session = await startSession();
    try {
      await session.withTransaction(async () => {
        const wallet = await WalletModel.findById(walletId).session(session);
        if (!wallet) throw new Error('NOT_FOUND');
        if (wallet.balance < amount) throw new Error('INSUFFICIENT_FUNDS');
        const sequence = (wallet.lastSequence ?? 0) + 1;
        await WalletEventModel.create([{ walletId, orgId, sequence, type: 'withdraw', amount, refId, by }], { session });
        wallet.balance -= amount;
        wallet.lastSequence = sequence;
        await wallet.save({ session });
      });
    } finally { session.endSession(); }
  }
};

import { WalletEventModel } from '../models/wallet-event.model';
import { WalletModel } from '../models/wallet.model';

export async function replayWallet(walletId: string) {
  const events = await WalletEventModel.find({ walletId }).sort({ sequence: 1 }).lean();
  let balance = 0;
  for (const e of events) {
    if (e.type === 'deposit' || e.type === 'transfer-in') balance += e.amount;
    else balance -= e.amount;
  }
  await WalletModel.updateOne({ _id: walletId }, { $set: { balance, lastSequence: events.at(-1)?.sequence ?? 0 } });
}

import crypto from 'node:crypto';
import bcrypt from 'bcrypt';

const DUMMY_HASH = bcrypt.hashSync('dummy-not-a-real-password', 12);

export function safeEqualTokens(a: string, b: string): boolean {
  const ab = Buffer.from(a);
  const bb = Buffer.from(b);
  if (ab.length !== bb.length) return false;
  return crypto.timingSafeEqual(ab, bb);
}

export async function constantCostPasswordCheck(presented: string, storedHash: string | null) {
  await bcrypt.compare(presented, storedHash ?? DUMMY_HASH);
}

export async function jitter(minMs = 30, maxMs = 90) {
  const ms = minMs + Math.random() * (maxMs - minMs);
  await new Promise(r => setTimeout(r, ms));
}

import { Request, Response, NextFunction } from 'express';
import { UserModel } from '../models/user.model';
import { constantCostPasswordCheck, jitter, safeEqualTokens } from '../lib/timing';
import bcrypt from 'bcrypt';
import { HttpError } from '../errors/http-error';

export const login = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { email, password } = req.body;
    const user = await UserModel.findOne({ email });
    const ok = await bcrypt.compare(password, user?.passwordHash ?? '$2b$12$invalidinvalidinvalidinvalidinvalidinvalidinvalidinvalid');
    if (!user || !ok) {
      await jitter();
      throw new HttpError(401, 'INVALID_CREDENTIALS');
    }
    res.json({ token: 'redacted-for-example', user: { id: user._id, email: user.email } });
  } catch (err) { next(err); }
};

export const verifyToken = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const presented = req.body.token as string;
    const stored = 'expected-token-fetched-from-db';
    if (!safeEqualTokens(presented, stored)) throw new HttpError(401, 'INVALID');
    res.json({ ok: true });
  } catch (err) { next(err); }
};

import React from 'react';
import { fetchUsers, deleteUser } from '../../api/users';

type User = { id: string; name: string };
type State = { users: User[]; loading: boolean; error: string | null };

export class UserList extends React.Component<{}, State> {
  state: State = { users: [], loading: false, error: null };
  mounted = false;
  async componentDidMount() {
    this.mounted = true;
    this.setState({ loading: true });
    try { const users = await fetchUsers(); if (this.mounted) this.setState({ users, loading: false }); }
    catch (e) { if (this.mounted) this.setState({ error: (e as Error).message, loading: false }); }
  }
  componentWillUnmount() { this.mounted = false; }
  handleDelete = async (id: string) => { await deleteUser(id); this.setState(s => ({ users: s.users.filter(u => u.id !== id) })); };
  render() {
    if (this.state.loading) return <div>Loading...</div>;
    if (this.state.error) return <div>{this.state.error}</div>;
    return <ul>{this.state.users.map(u => <li key={u.id}>{u.name} <button onClick={() => this.handleDelete(u.id)}>X</button></li>)}</ul>;
  }
}

import { useEffect, useState, useCallback } from 'react';
import { fetchUsers, deleteUser } from '../../api/users';

type User = { id: string; name: string };

export function UserList() {
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    fetchUsers()
      .then(u => { if (!cancelled) { setUsers(u); setLoading(false); } })
      .catch(e => { if (!cancelled) { setError((e as Error).message); setLoading(false); } });
    return () => { cancelled = true; };
  }, []);

  const handleDelete = useCallback(async (id: string) => {
    await deleteUser(id);
    setUsers(prev => prev.filter(u => u.id !== id));
  }, []);

  if (loading) return <div>Loading...</div>;
  if (error) return <div>{error}</div>;
  return <ul>{users.map(u => <li key={u.id}>{u.name} <button onClick={() => handleDelete(u.id)}>X</button></li>)}</ul>;
}

