import { io, Socket } from 'socket.io-client';

type Listener = (value: number) => void;
const refCounts = new Map<string, number>();
const listeners = new Map<string, Set<Listener>>();
let socket: Socket | null = null;

function ensureSocket(token: string) {
  if (socket) return socket;
  socket = io('/counters', { auth: { token }, transports: ['websocket'] });
  socket.on('value', ({ name, value }: { name: string; value: number }) => {
    for (const l of listeners.get(name) ?? []) l(value);
  });
  return socket;
}

export function subscribeCounter(token: string, name: string, listener: Listener) {
  const s = ensureSocket(token);
  const set = listeners.get(name) ?? new Set();
  set.add(listener);
  listeners.set(name, set);
  const count = (refCounts.get(name) ?? 0) + 1;
  refCounts.set(name, count);
  if (count === 1) s.emit('subscribe', name);
  return () => {
    set.delete(listener);
    const next = (refCounts.get(name) ?? 1) - 1;
    refCounts.set(name, next);
    if (next === 0) { s.emit('unsubscribe', name); listeners.delete(name); refCounts.delete(name); }
  };
}

