import { Server, Socket } from 'socket.io';

type Pos = { x: number; y: number; z: number };
const players = new Map<string, { id: string; pos: Pos; lastInput: number }>();

export function attachGameNamespace(io: Server) {
  const ns = io.of('/game');
  ns.on('connection', (socket: Socket) => {
    const id = (socket as any).data.userId as string;
    players.set(id, { id, pos: { x: 0, y: 0, z: 0 }, lastInput: Date.now() });
    socket.join('arena');
    socket.emit('snapshot', Array.from(players.values()));
    socket.to('arena').emit('join', { id, pos: { x: 0, y: 0, z: 0 } });
    socket.on('input', (pos: Pos) => {
      const p = players.get(id); if (!p) return;
      p.pos = pos; p.lastInput = Date.now();
    });
    socket.on('disconnect', () => { players.delete(id); ns.to('arena').emit('leave', { id }); });
  });
  setInterval(() => {
