import { useFrame } from '@react-three/fiber';
import { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { io } from 'socket.io-client';

type Pos = { x: number; y: number; z: number };
type Remote = { id: string; pos: Pos; target: Pos };

const players = new Map<string, Remote>();

export function Players({ token, myId }: { token: string; myId: string }) {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const m = new THREE.Matrix4();

  useEffect(() => {
    const socket = io('/game', { auth: { token }, transports: ['websocket'] });
    socket.on('snapshot', (snap: { id: string; pos: Pos }[]) => { for (const p of snap) if (p.id !== myId) players.set(p.id, { id: p.id, pos: p.pos, target: p.pos }); });
    socket.on('join', ({ id, pos }: { id: string; pos: Pos }) => { if (id !== myId) players.set(id, { id, pos, target: pos }); });
    socket.on('tick', (tick: { id: string; pos: Pos }[]) => {
      for (const p of tick) {
        if (p.id === myId) continue;
        const r = players.get(p.id);
        if (r) r.target = p.pos; else players.set(p.id, { id: p.id, pos: p.pos, target: p.pos });
      }
    });
    socket.on('leave', ({ id }: { id: string }) => players.delete(id));
    return () => { socket.disconnect(); };
  }, [token, myId]);

  useFrame(() => {
    const mesh = meshRef.current; if (!mesh) return;
    let i = 0;
    for (const p of players.values()) {
      p.pos.x += (p.target.x - p.pos.x) * 0.2;
      p.pos.y += (p.target.y - p.pos.y) * 0.2;
      p.pos.z += (p.target.z - p.pos.z) * 0.2;
      m.setPosition(p.pos.x, p.pos.y, p.pos.z);
      mesh.setMatrixAt(i, m);
      i++;
    }
    mesh.count = i;
    mesh.instanceMatrix.needsUpdate = true;
  });

  return <instancedMesh ref={meshRef} args={[undefined, undefined, 100]}><sphereGeometry args={[0.4, 12, 8]} /><meshStandardMaterial color="#5b8def" /></instancedMesh>;
}

