import { Upload } from '@aws-sdk/lib-storage';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
import { GetObjectCommand } from '@aws-sdk/client-s3';
import archiver from 'archiver';
import { auditLog } from '../services/audit.service';

const s3 = new S3Client({ region: process.env.AWS_REGION! });
const BUCKET = process.env.EXPORT_BUCKET!;

export async function exportTenant(jobId: string) {
  const job = await ExportJobModel.findById(jobId);
  if (!job) return;
  job.status = 'running'; await job.save();
  try {
    const archive = archiver('zip');
    const key = `exports/tenant/${job.orgId}/${job._id}.zip`;
    const upload = new Upload({ client: s3, params: { Bucket: BUCKET, Key: key, Body: archive, ContentType: 'application/zip' } });
    const collections: Array<[string, AsyncIterable<unknown>]> = [
      ['orders.json', toJsonStream(OrderModel.find({ orgId: job.orgId }).cursor())],
      ['users.json', toJsonStream(UserModel.find({ orgId: job.orgId }).cursor())]
    ];
    for (const [name, stream] of collections) {
      const buf = await consume(stream);
      archive.append(buf, { name });
    }
    archive.finalize();
    await upload.done();
    const url = await getSignedUrl(s3, new GetObjectCommand({ Bucket: BUCKET, Key: key }), { expiresIn: 3600 });
    job.status = 'done'; job.downloadUrl = url; await job.save();
    await auditLog({ actorId: String(job.requestedBy), action: 'tenant.exported', target: String(job.orgId) });
  } catch (err) { job.status = 'failed'; job.error = (err as Error).message; await job.save(); }
}

async function* toJsonStream(cursor: AsyncIterable<unknown>): AsyncIterable<string> {
  yield '[';
  let first = true;
  for await (const doc of cursor) { if (!first) yield ','; else first = false; yield JSON.stringify(doc); }
  yield ']';
}

async function consume(stream: AsyncIterable<unknown>): Promise<Buffer> {
  const parts: string[] = [];
  for await (const part of stream) parts.push(String(part));
  return Buffer.from(parts.join(''));
}

