import { useEffect, useState, useCallback } from 'react';

type Entry = { data: unknown; error: Error | null; updatedAt: number; subscribers: Set<() => void> };
const cache = new Map<string, Entry>();
const inFlight = new Map<string, Promise<unknown>>();

async function revalidate(key: string, fetcher: () => Promise<unknown>) {
  const existing = inFlight.get(key); if (existing) return existing;
  const p = (async () => {
    try {
      const data = await fetcher();
      const entry = cache.get(key) ?? { data: undefined, error: null, updatedAt: 0, subscribers: new Set() };
      entry.data = data; entry.error = null; entry.updatedAt = Date.now();
      cache.set(key, entry);
      for (const s of entry.subscribers) s();
    } catch (err) {
      const entry = cache.get(key) ?? { data: undefined, error: null, updatedAt: 0, subscribers: new Set() };
      entry.error = err as Error;
      cache.set(key, entry);
      for (const s of entry.subscribers) s();
    } finally { inFlight.delete(key); }
  })();
  inFlight.set(key, p);
  return p;
}

export function useResource<T>(key: string | null, fetcher: () => Promise<T>) {
  const [, force] = useState(0);
  useEffect(() => {
    if (!key) return;
    let entry = cache.get(key);
    if (!entry) { entry = { data: undefined, error: null, updatedAt: 0, subscribers: new Set() }; cache.set(key, entry); }
    const trigger = () => force(n => n + 1);
    entry.subscribers.add(trigger);
    if (entry.updatedAt === 0) void revalidate(key, fetcher);
    return () => { entry!.subscribers.delete(trigger); };
  }, [key]);

  useEffect(() => {
    if (!key) return;
    const onFocus = () => revalidate(key, fetcher);
    window.addEventListener('focus', onFocus);
    window.addEventListener('online', onFocus);
    return () => { window.removeEventListener('focus', onFocus); window.removeEventListener('online', onFocus); };
  }, [key, fetcher]);

  const mutate = useCallback(() => { if (key) void revalidate(key, fetcher); }, [key, fetcher]);
  const entry = key ? cache.get(key) : null;
  return { data: entry?.data as T | undefined, isLoading: !!key && entry?.updatedAt === 0, error: entry?.error ?? null, mutate };
}

