import { Request, Response, NextFunction } from 'express';
import sharp from 'sharp';
import fs from 'node:fs/promises';
import path from 'node:path';

const CACHE_DIR = '/var/image-cache';

export const serveImage = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { name, format, width } = req.params;
    const cached = path.join(CACHE_DIR, `${name}-${width}.${format}`);
    try { const buf = await fs.readFile(cached); return sendImage(res, format, buf); }
    catch { /* miss */ }
    const source = await fs.readFile(path.join('/var/images', name));
    const transformer = sharp(source).resize(Number(width), null, { fit: 'inside', withoutEnlargement: true });
    const out = format === 'avif' ? await transformer.avif({ quality: 50 }).toBuffer()
            : format === 'webp' ? await transformer.webp({ quality: 80 }).toBuffer()
            : await transformer.jpeg({ quality: 80 }).toBuffer();
    await fs.writeFile(cached, out);
    sendImage(res, format, out);
  } catch (err) { next(err); }
};

function sendImage(res: Response, format: string, buf: Buffer) {
  const type = format === 'avif' ? 'image/avif' : format === 'webp' ? 'image/webp' : 'image/jpeg';
  res.setHeader('content-type', type);
  res.setHeader('cache-control', 'public, max-age=31536000, immutable');
  res.send(buf);
}

