type Stroke = { id: string; points: { x: number; y: number }[]; color: string; width: number };
const boards = new Map<string, { strokes: Stroke[]; lastSnapshotAt: number }>();

export function attachWhiteboardNamespace(io: Server) {
  const ns = io.of('/whiteboard');
  ns.on('connection', (socket: Socket) => {
    socket.on('board:join', async (boardId: string) => {
      await socket.join(`board:${boardId}`);
      const snap = await WhiteboardSnapshotModel.findOne({ boardId }).sort({ at: -1 }).lean();
      const live = boards.get(boardId)?.strokes ?? [];
      socket.emit('board:snapshot', { strokes: [...(snap?.strokes ?? []), ...live] });
    });
    socket.on('stroke', async (boardId: string, stroke: Stroke) => {
      let b = boards.get(boardId);
      if (!b) { b = { strokes: [], lastSnapshotAt: Date.now() }; boards.set(boardId, b); }
      b.strokes.push(stroke);
      socket.to(`board:${boardId}`).emit('stroke', stroke);
      if (b.strokes.length > 200 || Date.now() - b.lastSnapshotAt > 30_000) {
        const previous = await WhiteboardSnapshotModel.findOne({ boardId }).sort({ at: -1 }).lean();
        await WhiteboardSnapshotModel.create({ boardId, strokes: [...(previous?.strokes ?? []), ...b.strokes], at: new Date() });
        b.strokes = []; b.lastSnapshotAt = Date.now();
      }
    });
  });
}

import { useEffect, useRef } from 'react';
import { io } from 'socket.io-client';

type Stroke = { id: string; points: { x: number; y: number }[]; color: string; width: number };

export function Whiteboard({ boardId, token, color = '#000', width = 2 }: { boardId: string; token: string; color?: string; width?: number }) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const socketRef = useRef<ReturnType<typeof io> | null>(null);
  const currentRef = useRef<Stroke | null>(null);

  function renderStroke(stroke: Stroke) {
    const ctx = canvasRef.current!.getContext('2d')!;
    ctx.strokeStyle = stroke.color; ctx.lineWidth = stroke.width;
    ctx.beginPath();
    stroke.points.forEach((p, i) => i === 0 ? ctx.moveTo(p.x, p.y) : ctx.lineTo(p.x, p.y));
    ctx.stroke();
  }

  useEffect(() => {
    const socket = io('/whiteboard', { auth: { token } });
    socketRef.current = socket;
    socket.emit('board:join', boardId);
    socket.on('board:snapshot', ({ strokes }: { strokes: Stroke[] }) => { for (const s of strokes) renderStroke(s); });
    socket.on('stroke', (s: Stroke) => renderStroke(s));
    return () => { socket.disconnect(); };
  }, [boardId, token]);

  const start = (e: React.MouseEvent) => { currentRef.current = { id: Math.random().toString(36).slice(2), points: [{ x: e.nativeEvent.offsetX, y: e.nativeEvent.offsetY }], color, width }; };
  const move = (e: React.MouseEvent) => {
    const stroke = currentRef.current; if (!stroke || e.buttons === 0) return;
    stroke.points.push({ x: e.nativeEvent.offsetX, y: e.nativeEvent.offsetY });
    renderStroke({ ...stroke, points: stroke.points.slice(-2) });
  };
  const end = () => {
    const stroke = currentRef.current; if (!stroke) return;
    socketRef.current?.emit('stroke', boardId, stroke);
    currentRef.current = null;
  };

  return <canvas ref={canvasRef} width={1200} height={800} className="border" onMouseDown={start} onMouseMove={move} onMouseUp={end} onMouseLeave={end} />;
}

