import { Schema, model, Types } from 'mongoose';
const CustomFieldDefSchema = new Schema({
  orgId: { type: Types.ObjectId, required: true, index: true },
  resourceType: { type: String, required: true },
  key: { type: String, required: true },
  type: { type: String, enum: ['string','number','boolean','date'], required: true },
  required: { type: Boolean, default: false }
}, { timestamps: true });
CustomFieldDefSchema.index({ orgId: 1, resourceType: 1, key: 1 }, { unique: true });
export const CustomFieldDefModel = model('CustomFieldDef', CustomFieldDefSchema);

import { CustomFieldDefModel } from '../models/custom-field-def.model';

type Defs = { key: string; type: string; required: boolean }[];
const cache = new Map<string, { defs: Defs; cachedAt: number }>();
const TTL_MS = 60_000;

async function loadDefs(orgId: string, resourceType: string): Promise<Defs> {
  const key = `${orgId}:${resourceType}`;
  const cached = cache.get(key);
  if (cached && Date.now() - cached.cachedAt < TTL_MS) return cached.defs;
  const defs = await CustomFieldDefModel.find({ orgId, resourceType }).lean();
  const result = defs.map(d => ({ key: d.key, type: d.type, required: d.required }));
  cache.set(key, { defs: result, cachedAt: Date.now() });
  return result;
}

export async function validateCustomFields(orgId: string, resourceType: string, input: Record<string, unknown> = {}): Promise<Record<string, unknown>> {
  const defs = await loadDefs(orgId, resourceType);
  const out: Record<string, unknown> = {};
  for (const def of defs) {
    const v = input[def.key];
    if (v === undefined || v === null) { if (def.required) throw new Error(`MISSING_REQUIRED:${def.key}`); continue; }
    switch (def.type) {
      case 'string': if (typeof v !== 'string') throw new Error(`TYPE_MISMATCH:${def.key}`); break;
      case 'number': if (typeof v !== 'number') throw new Error(`TYPE_MISMATCH:${def.key}`); break;
      case 'boolean': if (typeof v !== 'boolean') throw new Error(`TYPE_MISMATCH:${def.key}`); break;
      case 'date': if (isNaN(new Date(v as string).getTime())) throw new Error(`TYPE_MISMATCH:${def.key}`); break;
    }
    out[def.key] = v;
  }
  return out;
}

export function invalidateCustomFieldCache(orgId: string, resourceType: string) { cache.delete(`${orgId}:${resourceType}`); }

