import { redis } from '../infra/redis';

export async function riskScore(input: { ip: string; userAgent?: string }): Promise<number> {
  const ipKey = `risk:ip:${input.ip}`;
  const count = await redis.incr(ipKey);
  if (count === 1) await redis.expire(ipKey, 3600);
  let score = Math.min(10, Math.floor(count / 5));
  if (!input.userAgent || /bot|crawler|spider/i.test(input.userAgent)) score += 5;
  return Math.min(10, score);
}

export async function verifyCaptcha(token: string, remoteip: string): Promise<boolean> {
  const res = await fetch('https://challenges.cloudflare.com/turnstile/v0/siteverify', { method: 'POST', body: new URLSearchParams({ secret: process.env.TURNSTILE_SECRET!, response: token, remoteip }) });
  const data = await res.json() as { success: boolean };
  return data.success;
}

import { Request, Response, NextFunction } from 'express';
import { riskScore, verifyCaptcha } from '../services/risk.service';
import { UserModel } from '../models/user.model';
import bcrypt from 'bcrypt';

export const signup = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { email, password, captchaToken } = req.body;
    const score = await riskScore({ ip: req.ip ?? '0.0.0.0', userAgent: req.headers['user-agent'] });
    if (score >= 5) {
      if (!captchaToken) return res.status(403).json({ captchaRequired: true });
      const ok = await verifyCaptcha(captchaToken, req.ip ?? '0.0.0.0');
      if (!ok) return res.status(403).json({ captchaRequired: true });
    }
    const user = await UserModel.create({ email, passwordHash: await bcrypt.hash(password, 12) });
    res.status(201).json({ user: { id: user._id, email: user.email } });
  } catch (err) { next(err); }
};

import { useState } from 'react';

export function Signup() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [needsCaptcha, setNeedsCaptcha] = useState(false);
  const [captchaToken, setCaptchaToken] = useState<string | null>(null);

  const submit = async (e: React.FormEvent) => {
    e.preventDefault();
    const res = await fetch('/api/auth/signup', { method: 'POST', credentials: 'include', headers: { 'content-type': 'application/json' }, body: JSON.stringify({ email, password, captchaToken }) });
    if (res.status === 403) { setNeedsCaptcha(true); return; }
  };

  return (
    <form onSubmit={submit} className="space-y-3">
      <input type="email" value={email} onChange={e => setEmail(e.target.value)} className="border rounded p-2 w-full" />
      <input type="password" value={password} onChange={e => setPassword(e.target.value)} className="border rounded p-2 w-full" />
      {needsCaptcha && <div className="cf-turnstile" data-sitekey={import.meta.env.VITE_TURNSTILE_KEY} data-callback={(token: string) => setCaptchaToken(token)}></div>}
      <button type="submit" className="px-3 py-2 bg-black text-white rounded">Sign up</button>
    </form>
  );
}

