import { authenticator } from 'otplib';
import crypto from 'node:crypto';
import bcrypt from 'bcrypt';
import { UserModel } from '../models/user.model';
import { RecoveryCodeModel } from '../models/recovery-code.model';
import { TrustedDeviceModel } from '../models/trusted-device.model';

function hash(s: string) { return crypto.createHash('sha256').update(s).digest('hex'); }

export const twoFaService = {
  async startEnrollment(userId: string) {
    const secret = authenticator.generateSecret();
    const user = await UserModel.findById(userId);
    if (!user) throw new Error('NOT_FOUND');
    user.twoFaPendingSecret = secret;
    await user.save();
    const otpauth = authenticator.keyuri(user.email, 'AppName', secret);
    return { secret, otpauth };
  },
  async confirmEnrollment(userId: string, code: string): Promise<{ recoveryCodes: string[] }> {
    const user = await UserModel.findById(userId);
    if (!user?.twoFaPendingSecret) throw new Error('NO_PENDING');
    if (!authenticator.verify({ token: code, secret: user.twoFaPendingSecret })) throw new Error('INVALID_CODE');
    user.twoFaSecret = user.twoFaPendingSecret;
    user.twoFaPendingSecret = undefined;
    user.twoFaEnabled = true;
    await user.save();
    const codes: string[] = Array.from({ length: 8 }, () => crypto.randomBytes(5).toString('hex'));
    for (const c of codes) await RecoveryCodeModel.create({ userId, hash: await bcrypt.hash(c, 10), status: 'unused' });
    return { recoveryCodes: codes };
  },
  async verify(userId: string, code: string): Promise<boolean> {
    const user = await UserModel.findById(userId);
    if (!user?.twoFaEnabled || !user.twoFaSecret) return false;
    if (authenticator.verify({ token: code, secret: user.twoFaSecret })) return true;
    const candidates = await RecoveryCodeModel.find({ userId, status: 'unused' });
    for (const r of candidates) if (await bcrypt.compare(code, r.hash)) { r.status = 'used'; await r.save(); return true; }
    return false;
  },
  async trustDevice(userId: string): Promise<string> {
    const token = crypto.randomBytes(32).toString('base64url');
    await TrustedDeviceModel.create({ userId, tokenHash: hash(token), expiresAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000) });
    return token;
  },
  async isDeviceTrusted(userId: string, token: string): Promise<boolean> {
    const t = await TrustedDeviceModel.findOne({ userId, tokenHash: hash(token), expiresAt: { $gt: new Date() } });
    return !!t;
  }
};

import { Request, Response, NextFunction } from 'express';
import { twoFaService } from '../services/twofa.service';
import { HttpError } from '../errors/http-error';

export const startEnrollment = async (req: Request, res: Response, next: NextFunction) => {
  try { res.json(await twoFaService.startEnrollment(req.user!.id)); }
  catch (err) { next(err); }
};
export const confirmEnrollment = async (req: Request, res: Response, next: NextFunction) => {
  try { res.json(await twoFaService.confirmEnrollment(req.user!.id, req.body.code)); }
  catch (err) { next(err); }
};
export const verify = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const ok = await twoFaService.verify(req.user!.id, req.body.code);
    if (!ok) throw new HttpError(401, 'INVALID_CODE');
    if (req.body.trustDevice) {
      const token = await twoFaService.trustDevice(req.user!.id);
      res.cookie('td', token, { httpOnly: true, sameSite: 'lax', secure: true, maxAge: 30 * 24 * 60 * 60 * 1000 });
    }
    res.json({ ok: true });
  } catch (err) { next(err); }
};

